// ============================================================
// VALIDATE INCOMING PAYLOAD
// ============================================================
const body = $input.first().json.body;
if (!body) throw new Error('Empty payload');

const required = {
  'client_id': body.client_id,
  'plan_id': body.plan_id,
  'business_name': body.business_name,
  'business_type': body.business_type,
  'contact_number': body.contact_number,
  'primary_goal': body.primary_goal,
  'tone_of_voice': body.tone_of_voice,
  'fallback_behavior': body.fallback_behavior,
  'working_hours': body.working_hours,
  'location': body.location
};

const missing = Object.entries(required)
  .filter(([k, v]) => !v || (typeof v === 'string' && !v.trim()))
  .map(([k]) => k);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const validPlans = ['basic', 'business', 'enterprise'];
if (!validPlans.includes(body.plan_id)) {
  throw new Error(`Invalid plan_id: ${body.plan_id}`);
}

const phone = String(body.contact_number).replace(/\D/g, '');
if (phone.length < 10) {
  throw new Error(`Invalid contact_number: ${body.contact_number}`);
}

// Merge uploaded files into knowledge_base
let kb = body.knowledge_base || '';
if (Array.isArray(body.uploaded_files) && body.uploaded_files.length > 0) {
  for (const file of body.uploaded_files) {
    if (file.text) kb += '\n\n' + file.text;
  }
}

return {
  json: {
    ...$input.first().json,
    body: {
      ...body,
      knowledge_base: kb.trim(),
      contact_number_normalized: phone
    },
    validation_passed: true
  }
};

// ============================================================
// IDEMPOTENCY CHECK
// If this client_id was already processed → skip
// ============================================================
const existing = $input.all();
const clientId = $('VALIDATE_INTAKE').first().json.body.client_id;

if (existing.length > 0 && existing[0].json && existing[0].json.id) {
  const status = existing[0].json.fields?.status || '';
  if (['active', 'provisioning', 'confirmed'].includes(status)) {
    throw new Error(`Duplicate request: client_id ${clientId} already in status "${status}"`);
  }
}

return $('VALIDATE_INTAKE').first();

