// Extract customer_code from Telegram message text
const text = $json.callback_query.message.text || '';
const match = text.match(/كود العميل:\s*([^\n]+)/);

if (!match) throw new Error('Could not extract customer_code from message');

return { json: { customer_code: match[1].trim() } };

// ============================================================
// COMPILE & CLEAN KNOWLEDGE BASE
// ============================================================
const record = $input.first().json;
const f = record.fields || record;

let kb = String(f.knowledge_base || '').trim();

// Dedupe: if text appears twice back-to-back
if (kb.length > 200) {
  const half = Math.floor(kb.length / 2);
  const firstHalf = kb.substring(0, half).trim();
  const secondHalf = kb.substring(half).trim();
  const overlap = firstHalf.substring(0, Math.min(300, firstHalf.length));
  if (secondHalf.includes(overlap.substring(0, 200))) {
    kb = firstHalf;
  }
}

// Append structured products if present
let productsBlock = '';
try {
  const ps = typeof f.products_services === 'string'
    ? JSON.parse(f.products_services)
    : (f.products_services || []);
  if (Array.isArray(ps) && ps.length > 0) {
    productsBlock = '\n\n## المنتجات المُهيكلة\n';
    ps.forEach((p, i) => {
      productsBlock += `${i + 1}. ${p.name || ''} — ${p.price || ''}`;
      if (p.description) productsBlock += ` (${p.description})`;
      productsBlock += '\n';
    });
  }
} catch (e) { /* ignore */ }

const cleaned = kb + productsBlock;

return {
  json: {
    ...record,
    knowledge_base_clean: cleaned.trim(),
    knowledge_base_chars: cleaned.length
  }
};

// ============================================================
// ROUTE BY PLAN
// Determines which template branch to use
// ============================================================
const data = $input.first().json;
const planId = data.fields?.plan_id || 'starter';

const validPlans = ['starter', 'business', 'enterprise'];
const finalPlan = validPlans.includes(planId) ? planId : 'starter';

return {
  json: {
    ...data,
    plan_id_resolved: finalPlan,
    is_starter: finalPlan === 'starter',
    is_business: finalPlan === 'business',
    is_enterprise: finalPlan === 'enterprise'
  }
};

