// ============================================================
// EXTRACT & VALIDATE GENERATED PROMPT
// ============================================================
const prev = $('COMPILE_KNOWLEDGE_BASE').first().json;
const ai = $input.first().json;

let prompt = '';
if (typeof ai.output === 'string') prompt = ai.output;
else if (ai.output?.[0]?.content?.[0]?.text) prompt = ai.output[0].content[0].text;
else if (ai.message?.content) prompt = ai.message.content;
else if (ai.choices?.[0]?.message?.content) prompt = ai.choices[0].message.content;
else if (typeof ai.text === 'string') prompt = ai.text;
else throw new Error('Could not extract prompt from AI response');

prompt = prompt.trim();

const checks = {
  has_identity: prompt.includes('# هوية البوت') || prompt.includes('هوية البوت'),
  has_hard_rules: prompt.includes('قواعد صارمة') || prompt.includes('Hard Rules'),
  length_ok: prompt.length > 800 && prompt.length < 12000,
  is_arabic: /[\u0600-\u06FF]/.test(prompt),
  no_markdown_bold: !prompt.includes('**')
};

const all_passed = checks.has_identity && checks.length_ok && checks.is_arabic;

if (!all_passed) {
  throw new Error(`Prompt validation failed: ${JSON.stringify(checks)}`);
}

return {
  json: {
    ...prev,
    generated_system_prompt: prompt,
    validation: checks,
    validation_passed: all_passed,
    prompt_char_count: prompt.length
  }
};

// ============================================================
// INJECTION_ENGINE v5 — Factory v5 (3 templates structure)
// Reads template from $input (merge output)
// Direct field-level mutation of CLIENT_CONFIG (no string replace)
// Sanitizes for n8n REST API
// ============================================================

try {

  // ── 1. Load Sources ────────────────────────────────────
  const promptData   = $('EXTRACT_GENERATED_PROMPT').first().json;
  const templateData = $input.first().json;
  const driveData    = $('Copy Sheet template').first().json;

  const f             = promptData.fields || promptData;
  const templateStr   = templateData.template_json || '';
  const systemPrompt  = promptData.generated_system_prompt || '';
  const targetSheetId = driveData.id || '';

  // ── 2. Validate ────────────────────────────────────────
  if (!templateStr)   throw new Error('No template_json from MERGE_TEMPLATE');
  if (!targetSheetId) throw new Error('Sheet ID missing — Copy Sheet template failed');
  if (!systemPrompt)  throw new Error('System prompt empty — AI_PROMPT_BUILDER failed');

  // ── 3. Helpers ─────────────────────────────────────────
  function genUuid() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
      const r = Math.random() * 16 | 0;
      return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
  }

  // ── 4. Resolve Plan (handles array, slug, or record ID) ────
  let rawPlan = f.plan_id;
  let planRecordId = '';
  let planTier = 'starter';
  if (Array.isArray(rawPlan)) {
    planRecordId = String(rawPlan[0] || '');
    planTier = String(f.plan_tier || f.plan_slug || f.plan_name || 'starter').toLowerCase();
  } else if (typeof rawPlan === 'string') {
    if (rawPlan.startsWith('rec')) {
      planRecordId = rawPlan;
      planTier = String(f.plan_tier || f.plan_slug || f.plan_name || 'starter').toLowerCase();
    } else {
      planTier = rawPlan.toLowerCase();
      planRecordId = String(f.plan_record_id || '');
    }
  }
  const validTiers = ['starter','business','enterprise'];
  if (!validTiers.includes(planTier)) planTier = 'starter';

  // ── 5. Extract Client Fields ───────────────────────────
  const businessName = f.business_name      || 'Client Business';
  const businessType = f.business_type      || 'general';
  const contactPhone = String(f.contact_phone || '').replace(/\D/g, '');
  const orderId      = f.order_id           || 'UNKNOWN';
  const toneOfVoice  = f.tone_of_voice      || 'egyptian';
  const fallbackBeh  = f.fallback_behavior  || 'handover';
  const workingHours = f.working_hours      || 'غير محدد';

  // ── 6. Derived Values ──────────────────────────────────
  const slug         = orderId.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-');
  const webhookPath  = `bot-${slug}`;
  const webhookUuid  = genUuid();
  const workflowName = `🤖 Arq | ${businessName} | ${orderId}`;
  const instanceName = `bot_${orderId}`;

  // ── 7. Plan Config (overrides template hardcoded values) ────
  const planConfig = {
    starter:    { maxTokens: 800,  memoryWindow: 8,  model: 'anthropic/claude-haiku-4.5',  enableInvoices: false },
    business:   { maxTokens: 1024, memoryWindow: 12, model: 'anthropic/claude-sonnet-4.5', enableInvoices: true  },
    enterprise: { maxTokens: 1500, memoryWindow: 20, model: 'anthropic/claude-sonnet-4.5', enableInvoices: true  }
  };
  const cfg = planConfig[planTier];

  const escalationMsg = fallbackBeh === 'handover'
    ? `لحظة من فضلك، هحولك لزميل من فريق ${businessName} يساعدك أفضل 🙏`
    : `للمزيد من المساعدة، تواصل معانا على ${contactPhone}`;
  const fallbackMsg = `عذراً، حصل ظرف تقني بسيط. حاول تاني أو تواصل معانا.`;

  // ── 8. Sub-Workflow IDs (Razor's actual values) ────────
  const subWfIds = {
    wf_save_transaction:  '4UJrPVyoLgZ4d28l',
    wf_send_link:         'jExb5PYrZyTJxKKd',
    wf_escalation:        'oubJjWLRvTglbmdy',
    wf_send_presence:     'mJAK1gvtrbryJsUB',
    wf_log_conversation:  '26gNMLYgcyo4S1cw',
    wf_calculate_cost:    '1sx8sTJOiuwPeI62',
    wf_summarize:         'Oc5DlbCEALNsl1dF',
    wf_auto_tag:          '7YUp4Nalz4kgSZ1F',
    // Enterprise-only sub-workflows:
    wf_order_cancel:      'sqRNoOHtdU5AN5ke',
    wf_order_modify:      '0UgwLogMHfkK7a27',
    wf_order_track:       'TJjxTDa7MqYOnK6V',
    wf_promo_send:        'CH2uDK9bCFPF6pQy',
    wf_stock_check:       'bOhgmwRBKntJYqhj',
    wf_review_get:        '78I9IDMi51MRIkcr'
  };

  // ── 9. CLIENT_CONFIG override map ──────────────────────
  const ccOverrides = {
    bot_name:               `Arq | ${businessName}`,
    business_name:          businessName,
    order_id:               orderId,
    plan_id:                planRecordId || planTier,
    plan_tier:              planTier,
    system_prompt:          systemPrompt,
    working_hours:          workingHours,
    openrouter_model:       cfg.model,
    max_tokens:             cfg.maxTokens,
    memory_window:          cfg.memoryWindow,
    enable_invoices:        cfg.enableInvoices,
    fallback_message:       fallbackMsg,
    escalation_message:     escalationMsg,
    escalation_number:      contactPhone,
    instance_name:          instanceName,
    sheets_spreadsheet_id:  targetSheetId,
    domain_type:            businessType,
    admin_whatsapp:         contactPhone,
    brand_voice:            toneOfVoice,
    ...subWfIds
  };

  // Optional intake overrides
  if (f.currency)            ccOverrides.currency  = String(f.currency);
  if (f.tax_pct !== undefined) ccOverrides.tax_pct = Number(f.tax_pct);
  if (f.language)            ccOverrides.language  = String(f.language);
  if (f.openai_api_key)      ccOverrides.openai_api_key = String(f.openai_api_key);

  // ── 10. Parse & Mutate Template ────────────────────────
  let parsedWorkflow;
  try {
    parsedWorkflow = JSON.parse(templateStr);
  } catch (e) {
    throw new Error(`Template JSON parse failed: ${e.message}`);
  }

  parsedWorkflow.name = workflowName;

  for (const node of parsedWorkflow.nodes) {
    // Update webhook node
    if (node.type === 'n8n-nodes-base.webhook') {
      node.parameters = node.parameters || {};
      node.parameters.path = webhookPath;
      node.webhookId = webhookUuid;
    }
    // Update CLIENT_CONFIG SET node — field-by-field by name
    if (node.name === 'CLIENT_CONFIG' && node.parameters?.assignments?.assignments) {
      for (const a of node.parameters.assignments.assignments) {
        if (a.name in ccOverrides) {
          a.value = ccOverrides[a.name];
        }
      }
    }
  }

  // ── 11. Sanitize for n8n REST API ──────────────────────
  // Strip top-level keys the create-workflow endpoint rejects
  const apiRejectedKeys = [
    'id', 'versionId', 'meta', 'active', 'triggerCount',
    'createdAt', 'updatedAt', 'shared', 'staticData', 'isArchived',
    'activeVersion', 'activeVersionId', 'tags', 'pinData'
  ];
  for (const k of apiRejectedKeys) delete parsedWorkflow[k];

  // Settings whitelist (strips binaryMode etc.)
  if (parsedWorkflow.settings && typeof parsedWorkflow.settings === 'object') {
    const validSettingsKeys = [
      'executionOrder', 'saveExecutionProgress', 'saveManualExecutions',
      'callerPolicy', 'errorWorkflow', 'timezone', 'executionTimeout',
      'saveDataErrorExecution', 'saveDataSuccessExecution'
    ];
    const cleanSettings = {};
    for (const k of validSettingsKeys) {
      if (parsedWorkflow.settings[k] !== undefined) {
        cleanSettings[k] = parsedWorkflow.settings[k];
      }
    }
    if (!cleanSettings.executionOrder) cleanSettings.executionOrder = 'v1';
    parsedWorkflow.settings = cleanSettings;
  } else {
    parsedWorkflow.settings = { executionOrder: 'v1' };
  }

  // ── 12. Return ─────────────────────────────────────────
  return {
    json: {
      workflow:           parsedWorkflow,
      webhook_path:       webhookPath,
      webhook_uuid:       webhookUuid,
      workflow_name:      workflowName,
      instance_name:      instanceName,
      order_id:           orderId,
      business_name:      businessName,
      plan_id:            planRecordId || planTier,
      plan_tier:          planTier,
      plan_record_id:     planRecordId,
      target_sheet_id:    targetSheetId,
      contact_phone:      contactPhone,
      airtable_record_id: promptData.id || '',
      created_at:         new Date().toISOString()
    }
  };

} catch (error) {
  throw new Error(`INJECTION_ENGINE: ${error.message}`);
}

