const text = ($json.message_text || '').toLowerCase();

const injectionPatterns = [
  // Direct override attempts
  /ignore (all )?(previous|prior|above) (instructions|rules)/i,
  /forget (everything|all|previous)/i,
  /disregard (your|all|the) (instructions|rules|prompt)/i,
  /you are now/i,
  /pretend (you are|to be)/i,
  /act as (if|though)/i,
  /(jailbreak|dan mode|developer mode)/i,
  /system prompt/i,
  /reveal your (instructions|prompt|rules)/i,
  /what (are|is) your (instructions|prompt|rules)/i,

  // Arabic variants
  /تجاهل (كل |جميع )?(التعليمات|الأوامر|القواعد)/,
  /انسى (كل |جميع )/,
  /اعمل نفسك/,
  /كأنك/,
  /إيه (تعليماتك|الأوامر بتاعتك)/,
  /ما (هي )?(تعليماتك|الأوامر)/,
  /اظهر (لي )?الـ?\s?prompt/,
  /قول لي (الـ )?prompt/,
];

const isInjection = injectionPatterns.some(p => p.test(text));

return {
  json: {
    ...$json,
    is_injection_attempt: isInjection,
    safe_to_process: !isInjection
  }
