const data = $json;
const cfg = $('CLIENT_CONFIG').first().json;

let reply = '';
if (data.is_injection_attempt) {
  reply = `أنا مساعد خدمة عملاء ${cfg.business_name}. هل تحب أساعدك في حاجة بخصوص النشاط؟`;
} else if (data.media_rejection_msg) {
  reply = data.media_rejection_msg;
} else if (!(data.message_text || '').trim()) {
  reply = 'مقدرتش أقرأ رسالتك. اكتبها تاني لو سمحت 🙏';
} else {
  reply = cfg.fallback_message;
}

return {
  json: {
    ...data,
    final_reply: reply,
    skip_ai: true,
    skip_log: !!data.is_injection_attempt
