// 1. دالة هندمة الأرقام الشاملة لمصر والدول العربية والأجنبية
function formatPhoneNumber(phone) {
    if (!phone) return '';

    // تنظيف الرقم من أي مسافات، أقواس، أو علامات مثل (+)
    let cleaned = phone.toString().replace(/[\s\-\(\)\+]/g, '');

    // إزالة الأصفار البادئة الزائدة (مثل 0020 تصبح 20)
    cleaned = cleaned.replace(/^00/, '');

    // التعامل مع الأرقام المصرية (الأولوية الأساسية)
    // إذا كان الرقم يبدأ بـ 01 ومتبوع بـ 9 أرقام (إجمالي 11 رقم)
    if (/^01[0125]\d{8}$/.test(cleaned)) {
        return '20' + cleaned.substring(1); // حذف الـ 0 وإضافة 20
    }
    // إذا كان الرقم مصري بس مكتوب 1[0125] على طول من غير 0 ولا 20 (إجمالي 10 أرقام)
    if (/^1[0125]\d{8}$/.test(cleaned)) {
        return '20' + cleaned;
    }
    // إذا كان الرقم مصري ومكتب صح بالصيغة الدولية 201...
    if (/^201[0125]\d{8}$/.test(cleaned)) {
        return cleaned;
    }

    // التعامل مع الأرقام الدولية (خارج مصر) - أشهر الدول العربية والأجنبية

    // السعودية: لو بدأ بـ 05 ومتبوع بـ 8 أرقام -> حط كود السعودية 966
    if (/^05\d{8}$/.test(cleaned)) {
        return '966' + cleaned.substring(1);
    }

    // التحقق من الصيغ الدولية الشهيرة مباشرة للتأكد من سلامتها:
    const internationalPatterns = [
        /^9665\d{8}$/,      // السعودية
        /^9715\d{8}$/,      // الإمارات
        /^965\d{8}$/,       // الكويت
        /^974[3567]\d{7}$/, // قطر
        /^9689\d{7}$/,      // عمان
        /^973[36]\d{7}$/,   // البحرين
        /^9627[789]\d{7}$/, // الأردن
        /^9647[5789]\d{9}$/,// العراق
        /^213[567]\d{8}$/,  // الجزائر
        /^212[67]\d{8}$/,   // المغرب
        /^216[259]\d{8}$/,  // تونس
        /^1\d{10}$/         // أمريكا / كندا
    ];

    for (let pattern of internationalPatterns) {
        if (pattern.test(cleaned)) {
            return cleaned; // الرقم دولي وسليم تماماً
        }
    }

    // محاولة إنقاذ للعملاء اللي بيكتبوا رقمهم الدولي بدايته 00 (وإحنا شيلنا الـ 00 فوق)
    if (cleaned.length >= 11 && !cleaned.startsWith('0')) {
        return cleaned;
    }

    // إذا لم يطابق أي شرط، رجع الرقم نظيف
    return cleaned; 
}

// 2. جلب البيانات القادمة من الـ Webhook الخاص بـ n8n
const inputData = items[0].json;

// 3. هندمة وتعديل الـ contact_number فقط داخل الـ body إن وجد
if (inputData.body && inputData.body.contact_number) {
    inputData.body.contact_number = formatPhoneNumber(inputData.body.contact_number);
}

// 4. إرجاع الـ Object بالكامل بعد تعديل الرقم بنجاح لـ n8n
return [{ json: inputData }];
